  const key = /* generate key logic */;
  return key;
};

yourSchema.pre('findOne', cacheMiddleware(generateCacheKey, 60));

const YourModel = mongoose.model('YourModel', yourSchema);

export default YourModel;
```

In the example above, the `generateCacheKey` function is used as the key generator for the caching middleware. It receives the same arguments as the Mongoose query function (`this` context and query arguments) and transforms them into a unique key.

